import React from 'react';
import { View, Text } from 'react-native';
import axios from 'axios';

class App extends React.Component {
  constructor() {
    super();
    this.state = {
      userProfile: null,
      dataUpdates: [],
    };
  }

  componentDidMount() {
    this.fetchUserProfile();
  }

  fetchUserProfile() {
    axios.get('https://api.example.com/user')
      .then(response => {
        this.setState({ userProfile: response.data });
      })
      .catch(error => {
        console.log(error);
      });
  }

  updateData() {
    const data = {
      name: 'John Doe',
      age: 30,
    };
    axios.post('https://api.example.com/user', data)
      .then(response => {
        this.setState({ userProfile: response.data });
      })
      .catch(error => {
        console.log(error);
      });
  }

  render() {
    return (
      <View>
        <Text>{this.state.userProfile && this.state.userProfile.name}</Text>
        <Button onPress={this.updateData} title="Update Data" />
      </View>
    );
  }
}